// ----------------------------------------------------------------
// gzip 压缩字符串，返回 "gz:<base64>"
// ----------------------------------------------------------------

export async function compressContext(str: string): Promise<string> {
    if (!str) { return str }
    str = str.replaceAll(/\n{3,}/g, '\n\n').trim()
    const stream = new (window as any).CompressionStream('gzip')
    const writer = stream.writable.getWriter()
    writer.write(new TextEncoder().encode(str))
    writer.close()
    const chunks: Uint8Array[] = []
    const reader = stream.readable.getReader()
    while (true) {
        const { done, value } = await reader.read()
        if (done) { break }
        chunks.push(value)
    }
    const merged = new Uint8Array(chunks.reduce((n: number, c: Uint8Array) => n + c.length, 0))
    let offset = 0
    for (const c of chunks) { merged.set(c, offset); offset += c.length }
    let binary = ''
    for (let i = 0; i < merged.length; i++) { binary += String.fromCharCode(merged[i]) }
    return 'gz:' + btoa(binary)
}
```

